where recipient_member_id = #{recipientMemberId}
  and type = #{type}
  and reference_type = #{referenceType}
  and reference_id = #{referenceId}

select count(*)
from notifications n
where n.recipient_member_id = #{recipientMemberId}
  and n.read_at is null
  and n.type = #{type}
  and n.reference_type = #{referenceType}
  and exists (
      select 1
      from friendships f
      where f.id = n.reference_id
        and f.status = #{status}
  )

select 
from notifications n
where n.recipient_member_id = #{recipientMemberId}
  and n.read_at is null
  and n.type = #{type}
  and n.reference_type = #{referenceType}
  and exists (
      select 1
      from friendships f
      where f.id = n.reference_id
        and f.status = #{status}
  )
order by n.created_at desc, n.id desc
limit #{limit}

SELECT COUNT(*)
FROM notifications n
WHERE n.recipient_member_id = #{recipientMemberId}
  AND n.read_at IS NULL
  AND n.type = #{type}
  AND n.reference_type = #{referenceType}
  AND EXISTS (
      SELECT 1
      FROM course_invitations ci
      WHERE ci.id = n.reference_id
        AND ci.status = #{status}
  )

SELECT 
FROM notifications n
WHERE n.recipient_member_id = #{recipientMemberId}
  AND n.read_at IS NULL
  AND n.type = #{type}
  AND n.reference_type = #{referenceType}
  AND EXISTS (
      SELECT 1
      FROM course_invitations ci
      WHERE ci.id = n.reference_id
        AND ci.status = #{status}
  )
ORDER BY n.created_at DESC, n.id DESC
LIMIT #{limit}

